1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ---- Simplest cases / processing fee ----
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // ---- Base premiums for each main item type ----
15	  it("single sword (newcomer, first contract) → 100 base + 10 first-insurance + 5 fee = 115 G", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("single amulet (newcomer, first contract) → 60 base + 6 first-insurance + 5 fee = 71 G", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 71 }] });
28	  });
29	  it("single staff (newcomer, first contract) → 80 base + 8 first-insurance + 5 fee = 93 G", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 93 }] });
35	  });
36	  it("single potion (newcomer, first contract) → 40 base + 4 first-insurance + 5 fee = 49 G", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 49 }] });
42	  });
43	
44	  // ---- Components and blocks ----
45	  it("2 runes → 50 G base premium (no block) → total 60 G (50 base + 5 first-insurance + 5 fee)", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 60 }] });
51	  });
52	  it.todo("3 runes → 60 G base premium (block applies)");
53	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
54	  it.todo("7 runes → 175 G base premium (no block — block requires exactly 3)");
55	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
56	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
57	
58	  // ---- Item-specific modifiers ----
59	  it.todo("cursed item adds 50% risk surcharge to that item's base premium");
60	  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% risk surcharge");
61	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
62	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
63	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
64	
65	  // ---- Policy-wide modifiers ----
66	  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount on policy base");
67	  it.todo("customer with exactly 2 years → loyalty discount applies");
68	  it.todo("first insurance carries 10% surcharge per item");
69	  it.todo("each contract after the first gets 15% follow-up discount");
70	
71	  // ---- Modifier scope on multi-item policies ----
72	  it.todo("cursed sword + plain amulet → 160 base + 50 curse = 210 G before further modifiers and fee");
73	  it.todo("item-specific modifiers apply per item; policy-wide modifiers apply to policy base; fee added last");
74	
75	  // ---- Rounding ----
76	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
77	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
78	  it.todo("intermediate amounts kept as fractions; only final premium or payout rounded");
79	
80	  // ---- Integration premium examples ----
81	  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G (100 + 50 + 10 + 5 fee)");
82	  it.todo("long-standing (3 yr) second contract with cursed sword (steel, ench 7) → 160 G");
83	  it.todo("first insurance surcharge still applies per item even on follow-up contract");
84	
85	  // ---- Claim: standard reimbursement ----
86	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
87	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G");
88	
89	  // ---- Claim: enchantment threshold ----
90	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
91	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-ench wins, then deductible)");
92	
93	  // ---- Claim: dragon material ----
94	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
95	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins)");
96	
97	  // ---- Claim: deductible per damage event ----
98	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (100 deductible per item)");
99	
100	  // ---- Claim: multiple items of same type ----
101	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
102	  it.todo("two sword damages on policy with two swords → each treated as separate damage with its own deductible");
103	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero, claim rejected");
104	
105	  // ---- Claim: cap exhaustion ----
106	  it.todo("policy with sword + amulet → insurance sum 1600 G, cap 3200 G");
107	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value; premium modifiers don't raise cap)");
108	  it.todo("policy with sword + 3 runes (block) → insurance sum 1750 G; block discount affects premium only");
109	  it.todo("sword insured, cap 2000; two claims of 1500 — first payout 1400 (cap remaining 600), second payout 600 (cap remaining 0)");
110	
111	  // ---- Error / edge cases ----
112	  it.todo("quote includes item with unknown type (e.g. broomstick) → CLI exits non-zero, error to stderr, no results to stdout");
113	  it.todo("claim references damage entry whose item is not part of the policy → CLI exits non-zero, error to stderr");
114	  it.todo("claim contains a damage entry with amount: -200 → CLI exits non-zero, error to stderr");
115	
116	  // ---- CLI / schema integration ----
117	  it.todo("schema example: amulet quote then fire claim of 200 returns premium and payout/remainingCap");
118	});
