1	export type Item = Record<string, unknown>;
2	export type QuoteStep = { op: "quote"; items: Item[] };
3	export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<{ itemType: string; amount: number }> } };
4	export type Step = QuoteStep | ClaimStep;
5	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
6	export type QuoteResult = { premium: number };
7	export type ClaimResult = { payout: number; remainingCap: number };
8	export type ScenarioResult = { results: Array<QuoteResult | ClaimResult> };
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	};
20	
21	const itemBasePremium = (item: Item): number =>
22	  BASE_PREMIUM_BY_TYPE[item.type as string] ?? 0;
23	
24	const itemPremiumWithFirstInsuranceSurcharge = (item: Item): number => {
25	  const base = itemBasePremium(item);
26	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
27	};
28	
29	const quotePremium = (items: Item[]): number => {
30	  const itemsTotal = items.reduce(
31	    (sum, item) => sum + itemPremiumWithFirstInsuranceSurcharge(item),
32	    0,
33	  );
34	  return Math.ceil(itemsTotal + PROCESSING_FEE);
35	};
36	
37	export const runScenario = (scenario: Scenario): ScenarioResult => {
38	  const results = scenario.steps.map((step) => {
39	    if (step.op === "quote") {
40	      return { premium: quotePremium(step.items) };
41	    }
42	    return { payout: 0, remainingCap: 0 };
43	  });
44	  return { results };
45	};
